SELECT ?team (COUNT(?event) AS ?count)
WHERE {
  ?event wdt:P31 wd:Q1915733 ;
          wdt:P136 ?team .
  ?team wdt:P31 wd:Q168903 .
}
GROUP BY ?team
ORDER BY DESC(?count)
LIMIT 1

